-- Initial schema · Dream Starter Kit
-- Single baseline migration (squashed from the original 0001–0008 series;
-- re-squashed once more when the feature slices moved into extensions — their
-- tables now ship as ext_<slug>_* migrations under extensions/*/supabase).
-- Sections: identity · teams · files+storage. CORE tables only — feature
-- tables (chat, reminders, notifications, billing) live in their extensions.
-- Every table has RLS with owner-scoped policies — see docs/ERD.md (source of truth).

create extension if not exists pgcrypto;

-- ============================================================================
-- Identity
-- profiles: app-level user record, 1:1 with auth.users (same id). The anchor
-- for most RLS policies. Created by a trigger on signup. (docs/ERD.md)
-- ============================================================================

create table public.profiles (
  id uuid primary key references auth.users (id) on delete cascade,
  display_name text,
  avatar_url text,
  created_at timestamptz not null default now(),
  is_staff boolean not null default false
);

comment on table public.profiles is
  'App-level user record, 1:1 with auth.users (same id). Created by handle_new_user() on signup.';

comment on column public.profiles.is_staff is
  'Grants access to the Payload CMS admin via the Supabase->Payload SSO bridge. The first signup is auto-flagged; default-deny otherwise.';

-- Mirror auth.users -> profiles on signup. SECURITY DEFINER so it can insert
-- regardless of RLS; empty search_path is the Supabase security best practice
-- (every reference is schema-qualified). The FIRST profile created is flagged
-- staff (the founder/admin) — default-deny for everyone after.
create or replace function public.handle_new_user()
returns trigger
language plpgsql
security definer
set search_path = ''
as $$
begin
  insert into public.profiles (id, display_name, avatar_url, is_staff)
  values (
    new.id,
    coalesce(
      new.raw_user_meta_data ->> 'display_name',
      new.raw_user_meta_data ->> 'name',
      split_part(coalesce(new.email, ''), '@', 1)
    ),
    new.raw_user_meta_data ->> 'avatar_url',
    -- First profile in the table becomes staff (the founder/admin).
    (select count(*) = 0 from public.profiles)
  )
  on conflict (id) do nothing;
  return new;
end;
$$;

create trigger on_auth_user_created
  after insert on auth.users
  for each row execute function public.handle_new_user();

-- RLS: a user sees/updates only their own profile. Inserts happen via the
-- trigger (SECURITY DEFINER); deletes cascade from auth.users.
alter table public.profiles enable row level security;

create policy "profiles: select own"
  on public.profiles for select to authenticated
  using (id = (select auth.uid()));

create policy "profiles: update own"
  on public.profiles for update to authenticated
  using (id = (select auth.uid()))
  with check (id = (select auth.uid()));

-- Prevent privilege escalation: the "profiles: update own" RLS policy would otherwise
-- let a user flip their own is_staff. A column-level revoke can't subtract from a
-- table-level grant, so revoke table UPDATE and re-grant only the user-editable columns.
-- (RLS still scopes updates to the user's own row; SECURITY DEFINER functions and the
-- service_role keep full access and set is_staff out-of-band.)
revoke update on public.profiles from authenticated, anon;
grant update (display_name, avatar_url) on public.profiles to authenticated;

-- ============================================================================
-- Teams / multi-tenancy (optional — drop for single-user apps)
-- organizations, memberships, invitations. Org-scoped RLS uses SECURITY DEFINER
-- helpers to avoid infinite recursion on the memberships table. (docs/ERD.md)
-- ============================================================================

create table public.organizations (
  id uuid primary key default gen_random_uuid(),
  name text not null,
  owner_id uuid not null references public.profiles (id) on delete cascade,
  created_at timestamptz not null default now()
);
create index on public.organizations (owner_id);

create table public.memberships (
  id uuid primary key default gen_random_uuid(),
  org_id uuid not null references public.organizations (id) on delete cascade,
  user_id uuid not null references public.profiles (id) on delete cascade,
  role text not null default 'member' check (role in ('owner', 'admin', 'member')),
  created_at timestamptz not null default now(),
  unique (org_id, user_id)
);
-- Indexes on FKs used in RLS predicates.
create index on public.memberships (org_id);
create index on public.memberships (user_id);

create table public.invitations (
  id uuid primary key default gen_random_uuid(),
  org_id uuid not null references public.organizations (id) on delete cascade,
  email text not null,
  role text not null default 'member' check (role in ('owner', 'admin', 'member')),
  status text not null default 'pending' check (status in ('pending', 'accepted')),
  created_at timestamptz not null default now()
);
create index on public.invitations (org_id);

-- Membership helpers. SECURITY DEFINER runs as the function owner, so the
-- internal SELECT on memberships does NOT re-trigger memberships' RLS (which
-- would recurse). This is the canonical Supabase pattern.
create or replace function public.is_org_member(_org uuid)
returns boolean language sql security definer set search_path = '' stable as $$
  select exists (
    select 1 from public.memberships m
    where m.org_id = _org and m.user_id = (select auth.uid())
  );
$$;

create or replace function public.is_org_admin(_org uuid)
returns boolean language sql security definer set search_path = '' stable as $$
  select exists (
    select 1 from public.memberships m
    where m.org_id = _org
      and m.user_id = (select auth.uid())
      and m.role in ('owner', 'admin')
  );
$$;

-- On org creation, enroll the owner as an 'owner' member (avoids the
-- chicken-and-egg where the admin-only insert policy would block the first row).
create or replace function public.handle_new_organization()
returns trigger language plpgsql security definer set search_path = '' as $$
begin
  insert into public.memberships (org_id, user_id, role)
  values (new.id, new.owner_id, 'owner')
  on conflict (org_id, user_id) do nothing;
  return new;
end;
$$;

create trigger on_organization_created
  after insert on public.organizations
  for each row execute function public.handle_new_organization();

alter table public.organizations enable row level security;
alter table public.memberships enable row level security;
alter table public.invitations enable row level security;

-- organizations: members read; owner creates/updates/deletes.
create policy "orgs: select if member"
  on public.organizations for select to authenticated
  using (owner_id = (select auth.uid()) or public.is_org_member(id));
create policy "orgs: insert own"
  on public.organizations for insert to authenticated
  with check (owner_id = (select auth.uid()));
create policy "orgs: update owner"
  on public.organizations for update to authenticated
  using (owner_id = (select auth.uid()))
  with check (owner_id = (select auth.uid()));
create policy "orgs: delete owner"
  on public.organizations for delete to authenticated
  using (owner_id = (select auth.uid()));

-- memberships: members read co-members; admins manage. The first (owner) row
-- is created by the trigger above (SECURITY DEFINER).
create policy "memberships: select if member"
  on public.memberships for select to authenticated
  using (public.is_org_member(org_id));
create policy "memberships: admins insert"
  on public.memberships for insert to authenticated
  with check (public.is_org_admin(org_id));
create policy "memberships: admins update"
  on public.memberships for update to authenticated
  using (public.is_org_admin(org_id))
  with check (public.is_org_admin(org_id));
create policy "memberships: admins delete"
  on public.memberships for delete to authenticated
  using (public.is_org_admin(org_id));

-- invitations: org admins manage.
create policy "invitations: admins all"
  on public.invitations for all to authenticated
  using (public.is_org_admin(org_id))
  with check (public.is_org_admin(org_id));

-- ============================================================================
-- Files + Storage
-- `files` is metadata for objects in Supabase Storage. The bucket's RLS lives on
-- storage.objects, path-prefixed by user id (convention: "<user_id>/..."),
-- mirroring the files table's ownership. (docs/ERD.md)
-- ============================================================================

create table public.files (
  id uuid primary key default gen_random_uuid(),
  user_id uuid not null references public.profiles (id) on delete cascade,
  bucket text not null default 'user-files',
  path text not null, -- Storage object path, e.g. "<user_id>/avatar.png"
  mime_type text,
  size_bytes bigint,
  created_at timestamptz not null default now(),
  unique (bucket, path)
);
create index on public.files (user_id);

alter table public.files enable row level security;

create policy "files: own"
  on public.files for all to authenticated
  using (user_id = (select auth.uid()))
  with check (user_id = (select auth.uid()));

-- Private bucket for user uploads.
insert into storage.buckets (id, name, public)
values ('user-files', 'user-files', false)
on conflict (id) do nothing;

-- Storage RLS: a user may only touch objects under their own "<user_id>/" prefix.
create policy "user-files: select own"
  on storage.objects for select to authenticated
  using (bucket_id = 'user-files' and (storage.foldername(name))[1] = (select auth.uid())::text);

create policy "user-files: insert own"
  on storage.objects for insert to authenticated
  with check (bucket_id = 'user-files' and (storage.foldername(name))[1] = (select auth.uid())::text);

create policy "user-files: update own"
  on storage.objects for update to authenticated
  using (bucket_id = 'user-files' and (storage.foldername(name))[1] = (select auth.uid())::text)
  with check (bucket_id = 'user-files' and (storage.foldername(name))[1] = (select auth.uid())::text);

create policy "user-files: delete own"
  on storage.objects for delete to authenticated
  using (bucket_id = 'user-files' and (storage.foldername(name))[1] = (select auth.uid())::text);

-- Billing extension · initial schema (Stripe-synced mirror)
-- Clients may READ their own customer/subscription rows; the product catalog is
-- world-readable. NO write policies exist for clients — the Stripe webhook
-- (billing-stripe-webhook edge function) writes these using the service role,
-- which bypasses RLS entirely. DDL is reattach-friendly (if not exists /
-- drop-then-create policies) so a reinstall after `ext remove --keep-data`
-- adopts the surviving tables.

create table if not exists public.ext_billing_customers (
  id uuid primary key default gen_random_uuid(),
  user_id uuid not null unique references public.profiles (id) on delete cascade,
  stripe_customer_id text not null unique,
  created_at timestamptz not null default now()
);
create index if not exists ext_billing_customers_user_id_idx
  on public.ext_billing_customers (user_id);

create table if not exists public.ext_billing_products (
  id text primary key, -- Stripe product id
  active boolean not null default true,
  name text,
  description text,
  image text,
  metadata jsonb,
  created_at timestamptz not null default now()
);

create table if not exists public.ext_billing_prices (
  id text primary key, -- Stripe price id
  product_id text references public.ext_billing_products (id) on delete cascade,
  active boolean not null default true,
  unit_amount integer,
  currency text,
  type text check (type in ('one_time', 'recurring')),
  interval text check (interval in ('day', 'week', 'month', 'year')),
  interval_count integer,
  metadata jsonb,
  created_at timestamptz not null default now()
);
create index if not exists ext_billing_prices_product_id_idx
  on public.ext_billing_prices (product_id);

create table if not exists public.ext_billing_subscriptions (
  id text primary key, -- Stripe subscription id
  user_id uuid not null references public.profiles (id) on delete cascade,
  price_id text references public.ext_billing_prices (id),
  status text check (
    status in (
      'trialing', 'active', 'past_due', 'canceled',
      'incomplete', 'incomplete_expired', 'unpaid', 'paused'
    )
  ),
  quantity integer,
  cancel_at_period_end boolean not null default false,
  current_period_end timestamptz,
  created_at timestamptz not null default now()
);
create index if not exists ext_billing_subscriptions_user_id_idx
  on public.ext_billing_subscriptions (user_id);
create index if not exists ext_billing_subscriptions_price_id_idx
  on public.ext_billing_subscriptions (price_id);

alter table public.ext_billing_customers enable row level security;
alter table public.ext_billing_products enable row level security;
alter table public.ext_billing_prices enable row level security;
alter table public.ext_billing_subscriptions enable row level security;

-- Read own only (no write policies => clients cannot write; webhook uses service role).
drop policy if exists "ext_billing_customers: select own" on public.ext_billing_customers;
create policy "ext_billing_customers: select own"
  on public.ext_billing_customers for select to authenticated
  using (user_id = (select auth.uid()));

drop policy if exists "ext_billing_subscriptions: select own" on public.ext_billing_subscriptions;
create policy "ext_billing_subscriptions: select own"
  on public.ext_billing_subscriptions for select to authenticated
  using (user_id = (select auth.uid()));

-- Public catalog: anyone may read products/prices (e.g. a pricing page).
drop policy if exists "ext_billing_products: read all" on public.ext_billing_products;
create policy "ext_billing_products: read all"
  on public.ext_billing_products for select to authenticated, anon
  using (true);

drop policy if exists "ext_billing_prices: read all" on public.ext_billing_prices;
create policy "ext_billing_prices: read all"
  on public.ext_billing_prices for select to authenticated, anon
  using (true);

-- AI Chat extension · initial schema
-- ext_chat_threads / ext_chat_messages back the in-app assistant (AI SDK via
-- the AI Gateway). token_usage supports cost/observability. DDL is
-- reattach-friendly (if not exists / drop-then-create policies) so a reinstall
-- after `ext remove --keep-data` adopts the surviving tables.

create table if not exists public.ext_chat_threads (
  id uuid primary key default gen_random_uuid(),
  user_id uuid not null references public.profiles (id) on delete cascade,
  title text,
  created_at timestamptz not null default now()
);
create index if not exists ext_chat_threads_user_id_idx
  on public.ext_chat_threads (user_id);

create table if not exists public.ext_chat_messages (
  id uuid primary key default gen_random_uuid(),
  thread_id uuid not null references public.ext_chat_threads (id) on delete cascade,
  role text not null check (role in ('user', 'assistant', 'system')),
  content text not null default '',
  token_usage jsonb,
  created_at timestamptz not null default now()
);
create index if not exists ext_chat_messages_thread_id_idx
  on public.ext_chat_messages (thread_id);

alter table public.ext_chat_threads enable row level security;
alter table public.ext_chat_messages enable row level security;

drop policy if exists "ext_chat_threads: own" on public.ext_chat_threads;
create policy "ext_chat_threads: own"
  on public.ext_chat_threads for all to authenticated
  using (user_id = (select auth.uid()))
  with check (user_id = (select auth.uid()));

-- Messages are reachable only through a thread the user owns.
drop policy if exists "ext_chat_messages: via own thread" on public.ext_chat_messages;
create policy "ext_chat_messages: via own thread"
  on public.ext_chat_messages for all to authenticated
  using (
    exists (
      select 1 from public.ext_chat_threads t
      where t.id = ext_chat_messages.thread_id and t.user_id = (select auth.uid())
    )
  )
  with check (
    exists (
      select 1 from public.ext_chat_threads t
      where t.id = ext_chat_messages.thread_id and t.user_id = (select auth.uid())
    )
  );

-- Notifications extension · initial schema
-- ext_notifications (in-app feed) + ext_notifications_push_tokens (Expo device
-- registrations). Strictly user-owned under RLS; servers write via the service
-- role. DDL is reattach-friendly (if not exists / drop-then-create policies)
-- so a reinstall after `ext remove --keep-data` adopts the surviving tables.

create table if not exists public.ext_notifications (
  id uuid primary key default gen_random_uuid(),
  user_id uuid not null references public.profiles (id) on delete cascade,
  type text not null,
  title text,
  body text,
  data jsonb not null default '{}'::jsonb,
  read_at timestamptz,
  created_at timestamptz not null default now()
);
create index if not exists ext_notifications_user_id_idx
  on public.ext_notifications (user_id);

create table if not exists public.ext_notifications_push_tokens (
  id uuid primary key default gen_random_uuid(),
  user_id uuid not null references public.profiles (id) on delete cascade,
  token text not null, -- Expo push token
  platform text not null check (platform in ('ios', 'android', 'web')),
  created_at timestamptz not null default now(),
  unique (user_id, token)
);
create index if not exists ext_notifications_push_tokens_user_id_idx
  on public.ext_notifications_push_tokens (user_id);

alter table public.ext_notifications enable row level security;
alter table public.ext_notifications_push_tokens enable row level security;

-- notifications are typically written by the server (service role), but a user
-- may read/mark-read/delete their own.
drop policy if exists "ext_notifications: own" on public.ext_notifications;
create policy "ext_notifications: own"
  on public.ext_notifications for all to authenticated
  using (user_id = (select auth.uid()))
  with check (user_id = (select auth.uid()));

drop policy if exists "ext_notifications_push_tokens: own"
  on public.ext_notifications_push_tokens;
create policy "ext_notifications_push_tokens: own"
  on public.ext_notifications_push_tokens for all to authenticated
  using (user_id = (select auth.uid()))
  with check (user_id = (select auth.uid()));

-- Reminders extension · initial schema
-- ext_reminders: user-owned scheduled nudges. DDL is reattach-friendly
-- (if not exists / drop-then-create policies) so a reinstall after
-- `ext remove --keep-data` adopts the surviving table.

create table if not exists public.ext_reminders (
  id uuid primary key default gen_random_uuid(),
  user_id uuid not null references public.profiles (id) on delete cascade,
  due_at timestamptz not null,
  channel text not null default 'push' check (channel in ('push', 'email')),
  status text not null default 'pending' check (status in ('pending', 'sent', 'canceled')),
  created_at timestamptz not null default now()
);
create index if not exists ext_reminders_user_id_idx
  on public.ext_reminders (user_id);
-- The scheduler (reminders-process edge function) scans due+pending.
create index if not exists ext_reminders_status_due_at_idx
  on public.ext_reminders (status, due_at);

alter table public.ext_reminders enable row level security;

drop policy if exists "ext_reminders: own" on public.ext_reminders;
create policy "ext_reminders: own"
  on public.ext_reminders for all to authenticated
  using (user_id = (select auth.uid()))
  with check (user_id = (select auth.uid()));

-- Demo extension · initial schema (owner-scoped, canonical RLS pattern).
create table if not exists public.ext_demo_items (
  id uuid primary key default gen_random_uuid(),
  user_id uuid not null references public.profiles (id) on delete cascade,
  title text not null,
  created_at timestamptz not null default now()
);
create index if not exists ext_demo_items_user_id_idx on public.ext_demo_items (user_id);

alter table public.ext_demo_items enable row level security;

drop policy if exists "ext_demo_items: own" on public.ext_demo_items;
create policy "ext_demo_items: own"
  on public.ext_demo_items for all to authenticated
  using (user_id = (select auth.uid()))
  with check (user_id = (select auth.uid()));

-- Teardown for the removed "demo" extension (pnpm ext remove).
-- Teardown for `pnpm ext remove demo` (skipped with --keep-data).
drop table if exists public.ext_demo_items cascade;
